#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <assert.h>

#include <omp.h>

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define ASSUMED_NR_CLUSTERS 32
#define FLT_MAX 3.40282347e+38

int num_threads_perdim = THREADS_PER_DIM;
int num_blocks_perdim = BLOCKS_PER_DIM;
int num_threads = THREADS_PER_DIM * THREADS_PER_DIM;
int num_blocks = BLOCKS_PER_DIM * BLOCKS_PER_DIM;

int *membership_new;
float *feature_d;
float *feature_flipped_d;
int *membership_d;
float *block_new_centers;
float *clusters_d;
float *block_clusters_d;
int *block_deltas_d;

void invert_mapping(float *input, float *output, int npoints, int nfeatures) {
    int totalThreads = num_threads_perdim * num_blocks_perdim * num_blocks_perdim;
    #pragma omp parallel for schedule(static)
    for (int point_id = 0; point_id < npoints; point_id++) {
        for (int i = 0; i < nfeatures; i++) {
            output[point_id + npoints * i] = input[point_id * nfeatures + i];
        }
    }
}

int setup(int argc, char** argv);

void allocateMemory(int npoints, int nfeatures, int nclusters, float **features) {
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0)
        num_blocks++;
    num_blocks_perdim = (int)sqrt((double)num_blocks);
    while (num_blocks_perdim * num_blocks_perdim < num_blocks)
        num_blocks_perdim++;
    num_blocks = num_blocks_perdim * num_blocks_perdim;

    membership_new = (int*)malloc(npoints * sizeof(int));
    for (int i = 0; i < npoints; i++) membership_new[i] = -1;

    block_new_centers = (float*)malloc(nclusters * nfeatures * sizeof(float));

    feature_flipped_d = (float*)malloc(npoints * nfeatures * sizeof(float));
    memcpy(feature_flipped_d, features[0], npoints * nfeatures * sizeof(float));
    feature_d = (float*)malloc(npoints * nfeatures * sizeof(float));

    invert_mapping(feature_flipped_d, feature_d, npoints, nfeatures);

    membership_d = (int*)malloc(npoints * sizeof(int));
    clusters_d = (float*)malloc(nclusters * nfeatures * sizeof(float));

#ifdef BLOCK_DELTA_REDUCE
    block_deltas_d = (int*)malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));
#endif

#ifdef BLOCK_CENTER_REDUCE
    block_clusters_d = (float*)malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
#endif
}

void deallocateMemory() {
    free(membership_new);
    free(block_new_centers);
    free(feature_d);
    free(feature_flipped_d);
    free(membership_d);
    free(clusters_d);
#ifdef BLOCK_CENTER_REDUCE
    free(block_clusters_d);
#endif
#ifdef BLOCK_DELTA_REDUCE
    free(block_deltas_d);
#endif
}

int kmeansPoint(float *features,
                int nfeatures,
                int npoints,
                int nclusters,
                int *membership,
                float *clusters,
                float *block_clusters,
                int *block_deltas) {
    int delta = 0;
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int nthreads = omp_get_num_threads();
        int points_per_thread = (npoints + nthreads - 1) / nthreads;
        int start = tid * points_per_thread;
        int end = start + points_per_thread;
        if (end > npoints) end = npoints;

        int local_delta = 0;

#ifdef BLOCK_CENTER_REDUCE
        int block_idx = tid;
        // Initialize block_clusters for this thread
        for (int j = 0; j < nclusters; j++) {
            for (int k = 0; k < nfeatures; k++) {
                block_clusters[block_idx * nclusters * nfeatures + j * nfeatures + k] = 0.f;
            }
        }
#endif

        for (int point_id = start; point_id < end; point_id++) {
            float min_dist = FLT_MAX;
            int index = -1;
            for (int i = 0; i < nclusters; i++) {
                float dist = 0.f;
                int cluster_base_index = i * nfeatures;
                for (int j = 0; j < nfeatures; j++) {
                    float diff = features[point_id + j * npoints] - clusters[cluster_base_index + j];
                    dist += diff * diff;
                }
                if (dist < min_dist) {
                    min_dist = dist;
                    index = i;
                }
            }
            if (membership[point_id] != index) {
                local_delta++;
            }
            membership[point_id] = index;

#ifdef BLOCK_CENTER_REDUCE
            // Accumulate new centers in block_clusters
            for (int j = 0; j < nfeatures; j++) {
                block_clusters[block_idx * nclusters * nfeatures + index * nfeatures + j] += features[point_id + j * npoints];
            }
#endif
        }
#ifdef BLOCK_DELTA_REDUCE
        block_deltas[tid] = local_delta;
#else
#pragma omp atomic
        delta += local_delta;
#endif
    }
#ifdef BLOCK_DELTA_REDUCE
    for (int i = 0; i < num_threads * num_blocks_perdim * num_blocks_perdim / num_threads; i++) {
        delta += block_deltas[i];
    }
#endif
    return delta;
}

int kmeansCuda(float **feature,
               int nfeatures,
               int npoints,
               int nclusters,
               int *membership,
               float **clusters,
               int *new_centers_len,
               float **new_centers) {
    int delta = 0;

    memcpy(membership_d, membership_new, npoints * sizeof(int));
    memcpy(clusters_d, clusters[0], nclusters * nfeatures * sizeof(float));

    delta = kmeansPoint(feature_d,
                        nfeatures,
                        npoints,
                        nclusters,
                        membership_d,
                        clusters_d,
                        block_clusters_d,
                        block_deltas_d);

    memcpy(membership_new, membership_d, npoints * sizeof(int));

#ifdef BLOCK_CENTER_REDUCE
    float *block_clusters_h = (float *)malloc(num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
    memcpy(block_clusters_h, block_clusters_d, num_blocks_perdim * num_blocks_perdim * nclusters * nfeatures * sizeof(float));
#endif
#ifdef BLOCK_DELTA_REDUCE
    int *block_deltas_h = (int *)malloc(num_blocks_perdim * num_blocks_perdim * sizeof(int));
    memcpy(block_deltas_h, block_deltas_d, num_blocks_perdim * num_blocks_perdim * sizeof(int));
#endif

    delta = 0;
    for (int i = 0; i < npoints; i++) {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i]) {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for (int j = 0; j < nfeatures; j++) {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for (int i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        delta += block_deltas_h[i];
    }
#endif
#ifdef BLOCK_CENTER_REDUCE
    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++) {
            block_new_centers[j * nfeatures + k] = 0.f;
        }
    }
    for (int i = 0; i < num_blocks_perdim * num_blocks_perdim; i++) {
        for (int j = 0; j < nclusters; j++) {
            for (int k = 0; k < nfeatures; k++) {
                block_new_centers[j * nfeatures + k] += block_clusters_h[i * nclusters * nfeatures + j * nfeatures + k];
            }
        }
    }

#ifdef CPU_CENTER_REDUCE
#endif

    for (int j = 0; j < nclusters; j++) {
        for (int k = 0; k < nfeatures; k++)
            new_centers[j][k] = block_new_centers[j * nfeatures + k];
    }
#endif

#ifdef BLOCK_CENTER_REDUCE
    free(block_clusters_h);
#endif
#ifdef BLOCK_DELTA_REDUCE
    free(block_deltas_h);
#endif

    return delta;
}

int main(int argc, char **argv) {
    setup(argc, argv);
    return 0;
}
